   245	void ConnectionManagerImpl::checkForDeferredClose(bool skip_delay_close) {
   246	  Network::ConnectionCloseType close = Network::ConnectionCloseType::FlushWriteAndDelay;
   247	  if (runtime_.snapshot().getBoolean(ConnectionManagerImpl::OptionallyDelayClose, true) &&
   248	      skip_delay_close) {
   249	    close = Network::ConnectionCloseType::FlushWrite;
   250	  }
   251	  if (drain_state_ == DrainState::Closing && streams_.empty() && !codec_->wantsToWrite()) {
   252	    // We are closing a draining connection with no active streams and the codec has
   253	    // nothing to write.
   254	    doConnectionClose(close, absl::nullopt,
   255	                      StreamInfo::LocalCloseReasons::get().DeferredCloseOnDrainedConnection);
   256	  }
