  1143	    // For egress (outbound) requests, pass the decorator's operation name (if defined and
  1144	    // propagation enabled) as a request header to enable the receiving service to use it in its
  1145	    // server span.
  1146	    if (!decorated_operation.empty() && state_.decorated_propagate_) {
  1147	      headers.setEnvoyDecoratorOperation(decorated_operation);
