  1199	    auto validation_result = header_validator_->validateRequestHeaders(*request_headers_);
  1200	    bool failure = !validation_result.ok();
  1201	    bool redirect = false;
  1202	    bool is_grpc = Grpc::Common::hasGrpcContentType(*request_headers_);
  1203	    std::string failure_details(validation_result.details());
  1204	    if (!failure) {
  1205	      auto transformation_result = header_validator_->transformRequestHeaders(*request_headers_);
  1206	      failure = !transformation_result.ok();
  1207	      redirect = transformation_result.action() ==
  1208	                 Http::ServerHeaderValidator::RequestHeadersTransformationResult::Action::Redirect;
  1209	      failure_details = std::string(transformation_result.details());
  1210	      if (redirect && !is_grpc) {
  1211	        connection_manager_.stats_.named_.downstream_rq_redirected_with_normalized_path_.inc();
  1212	      } else if (failure) {
  1213	        connection_manager_.stats_.named_.downstream_rq_failed_path_normalization_.inc();
  1214	      }
  1215	    }
  1216	    if (failure) {
  1217	      std::function<void(ResponseHeaderMap & headers)> modify_headers;
  1218	      Code response_code = failure_details == Http1ResponseCodeDetail::get().InvalidTransferEncoding
  1219	                               ? Code::NotImplemented
  1220	                               : Code::BadRequest;
  1221	      absl::optional<Grpc::Status::GrpcStatus> grpc_status;
  1222	      if (redirect && !is_grpc) {
  1223	        response_code = Code::TemporaryRedirect;
  1224	        modify_headers = [new_path = request_headers_->Path()->value().getStringView()](
  1225	                             Http::ResponseHeaderMap& response_headers) -> void {
  1226	          response_headers.addReferenceKey(Http::Headers::get().Location, new_path);
  1227	        };
  1228	      } else if (is_grpc) {
  1229	        grpc_status = Grpc::Status::WellKnownGrpcStatus::Internal;
  1230	      }
  1231	
  1232	      filter_manager_.streamInfo().setResponseFlag(
  1233	          StreamInfo::CoreResponseFlag::DownstreamProtocolError);
  1234	
  1235	      // H/2 codec was resetting requests that were rejected due to headers with underscores,
  1236	      // instead of sending 400. Preserving this behavior for now.
  1237	      // TODO(#24466): Make H/2 behavior consistent with H/1 and H/3.
  1238	      if (failure_details == UhvResponseCodeDetail::get().InvalidUnderscore &&
  1239	          connection_manager_.codec_->protocol() == Protocol::Http2) {
  1240	        filter_manager_.streamInfo().setResponseCodeDetails(failure_details);
  1241	        resetStream();
  1242	      } else {
  1243	        sendLocalReply(response_code, "", modify_headers, grpc_status, failure_details);
  1244	        if (!response_encoder_->streamErrorOnInvalidHttpMessage() &&
  1245	            !streamErrorOnlyErrors(failure_details)) {
  1246	          connection_manager_.handleCodecError(failure_details);
  1247	        }
  1248	      }
  1249	      return false;
  1250	    }
  1251	  }
  1252	
  1253	  return true;
  1254	}
