  1256	bool ConnectionManagerImpl::ActiveStream::validateTrailers(RequestTrailerMap& trailers) {
  1257	  if (!header_validator_) {
  1258	    return true;
  1259	  }
  1260	
  1261	  auto validation_result = header_validator_->validateRequestTrailers(trailers);
  1262	  std::string failure_details(validation_result.details());
  1263	  if (validation_result.ok()) {
  1264	    auto transformation_result = header_validator_->transformRequestTrailers(trailers);
  1265	    if (transformation_result.ok()) {
  1266	      return true;
  1267	    }
  1268	    failure_details = std::string(transformation_result.details());
  1269	  }
  1270	
  1271	  Code response_code = Code::BadRequest;
  1272	  absl::optional<Grpc::Status::GrpcStatus> grpc_status;
  1273	  if (Grpc::Common::hasGrpcContentType(*request_headers_)) {
  1274	    grpc_status = Grpc::Status::WellKnownGrpcStatus::Internal;
  1275	  }
  1276	
  1277	  filter_manager_.streamInfo().setResponseFlag(
  1278	      StreamInfo::CoreResponseFlag::DownstreamProtocolError);
  1279	
  1280	  // H/2 codec was resetting requests that were rejected due to headers with underscores,
  1281	  // instead of sending 400. Preserving this behavior for now.
  1282	  // TODO(#24466): Make H/2 behavior consistent with H/1 and H/3.
  1283	  if (failure_details == UhvResponseCodeDetail::get().InvalidUnderscore &&
  1284	      connection_manager_.codec_->protocol() == Protocol::Http2) {
  1285	    filter_manager_.streamInfo().setResponseCodeDetails(failure_details);
  1286	    resetStream();
  1287	  } else {
  1288	    // TODO(#24735): Harmonize H/2 and H/3 behavior with H/1
  1289	    if (connection_manager_.codec_->protocol() < Protocol::Http2) {
  1290	      sendLocalReply(response_code, "", nullptr, grpc_status, failure_details);
