  2078	  const absl::string_view encoder_details = response_encoder_->getStream().responseDetails();
  2079	  ENVOY_STREAM_LOG(debug, "stream reset: reset reason: {}, response details: {}", *this,
  2080	                   Http::Utility::resetReasonToString(reset_reason),
