  2085	  // If the codec sets its responseDetails() for a reason other than peer reset, set a
  2086	  // DownstreamProtocolError. Either way, propagate details.
  2087	  if (reset_reason == StreamResetReason::ProtocolError ||
  2088	      (!encoder_details.empty() && reset_reason == StreamResetReason::LocalReset)) {
  2089	    filter_manager_.streamInfo().setResponseFlag(
  2090	        StreamInfo::CoreResponseFlag::DownstreamProtocolError);
  2091	  }
  2092	  if (!encoder_details.empty()) {
  2093	    if (reset_reason == StreamResetReason::ConnectError ||
  2094	        reset_reason == StreamResetReason::RemoteReset ||
  2095	        reset_reason == StreamResetReason::RemoteRefusedStreamReset) {
  2096	      filter_manager_.streamInfo().setResponseFlag(
  2097	          StreamInfo::CoreResponseFlag::DownstreamRemoteReset);
  2098	    }
  2099	    filter_manager_.streamInfo().setResponseCodeDetails(encoder_details);
  2100	  }
  2101	
  2102	  // Check if we're in the overload manager reset case.
  2103	  // encoder_details should be empty in this case as we don't have a codec error.
  2104	  if (encoder_details.empty() && reset_reason == StreamResetReason::OverloadManager) {
  2105	    filter_manager_.streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::OverloadManager);
  2106	    filter_manager_.streamInfo().setResponseCodeDetails(
  2107	        StreamInfo::ResponseCodeDetails::get().Overload);
  2108	  }
  2109	  filter_manager_.onDownstreamReset();
