  2123	bool ConnectionManagerImpl::ActiveStream::shouldSkipDeferredCloseDelay() const {
  2124	  // If HTTP/1.0 has no content length, it is framed by close and won't consider
  2125	  // the request complete until the FIN is read. Don't delay close in this case.
  2126	  const bool http_10_sans_cl = (connection_manager_.codec_->protocol() == Protocol::Http10) &&
  2127	                               (!response_headers_ || !response_headers_->ContentLength());
