  2583	void ConnectionManagerImpl::onDeferredRequestProcessing() {
  2584	  if (streams_.empty()) {
  2585	    return;
  2586	  }
  2587	  requests_during_dispatch_count_ = 1; // 1 stream is always let through
  2588	  // Streams are inserted at the head of the list. As such process deferred
  2589	  // streams in the reverse order.
  2590	  auto reverse_iter = std::prev(streams_.end());
  2591	  bool at_first_element = false;
  2592	  do {
  2593	    at_first_element = reverse_iter == streams_.begin();
  2594	    // Move the iterator to the previous item in case the `onDeferredRequestProcessing` call removes
  2595	    // the stream from the list.
  2596	    auto previous_element = std::prev(reverse_iter);
  2597	    bool was_deferred = (*reverse_iter)->onDeferredRequestProcessing();
  2598	    if (was_deferred && shouldDeferRequestProxyingToNextIoCycle()) {
  2599	      break;
  2600	    }
  2601	    reverse_iter = previous_element;
  2602	    // TODO(yanavlasov): see if `rend` can be used.
  2603	  } while (!at_first_element);
