   833	void FilterManager::decodeTrailers(ActiveStreamDecoderFilter* filter, RequestTrailerMap& trailers) {
   834	  // If a response is complete or a reset has been sent, filters do not care about further body
   835	  // data. Just drop it.
   836	  if (stopDecoderFilterChain()) {
   837	    return;
   838	  }
   839	
   840	  // Filter iteration may start at the current filter.
   841	  StreamDecoderFilters::Iterator entry =
   842	      commonDecodePrefix(filter, FilterIterationStartState::CanStartFromCurrent);
   843	  bool terminal_filter_reached = false;
   844	  ASSERT(!state_.decoder_filter_chain_complete_ || entry == decoder_filters_.end());
   845	
   846	  for (; entry != decoder_filters_.end(); entry++) {
   847	    ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
   848	    // If the filter pointed by entry has stopped for all frame type, return now.
   849	    if ((*entry)->stoppedAll()) {
   850	      return;
   851	    }
   852	    ASSERT(!(state_.filter_call_state_ & FilterCallState::DecodeTrailers));
   853	    state_.filter_call_state_ |= FilterCallState::DecodeTrailers;
   854	    FilterTrailersStatus status = (*entry)->handle_->decodeTrailers(trailers);
   855	    (*entry)->handle_->decodeComplete();
   856	    (*entry)->end_stream_ = true;
   857	    state_.filter_call_state_ &= ~FilterCallState::DecodeTrailers;
   858	    ENVOY_STREAM_LOG(trace, "decode trailers called: filter={} status={}", *this,
   859	                     (*entry)->filter_context_.config_name, static_cast<uint64_t>(status));
   860	    if (state_.decoder_filter_chain_aborted_) {
   861	      executeLocalReplyIfPrepared();
   862	      ENVOY_STREAM_LOG(trace,
   863	                       "decodeTrailers filter iteration aborted due to local reply: filter={}",
   864	                       *this, (*entry)->filter_context_.config_name);
   865	      status = FilterTrailersStatus::StopIteration;
   866	    }
   867	
   868	    processNewlyAddedMetadata();
   869	    // Check if the last filter has processed trailers
   870	    terminal_filter_reached = std::next(entry) == decoder_filters_.end();
   871	
   872	    if (!(*entry)->commonHandleAfterTrailersCallback(status) && !terminal_filter_reached) {
   873	      return;
   874	    }
   875	  }
   876	  disarmRequestTimeout();
   877	  maybeEndDecode(terminal_filter_reached);
