   998	void DownstreamFilterManager::sendLocalReply(
   999	    Code code, absl::string_view body,
  1000	    const std::function<void(ResponseHeaderMap& headers)>& modify_headers,
  1001	    const absl::optional<Grpc::Status::GrpcStatus> grpc_status, absl::string_view details) {
  1002	  ASSERT(!state_.under_on_local_reply_);
