  1004	  const bool is_grpc_request = state_.is_grpc_request_;
  1005	
  1006	  // Stop filter chain iteration if local reply was sent while filter decoding or encoding callbacks
  1007	  // are running.
  1008	  if (state_.filter_call_state_ & FilterCallState::IsDecodingMask) {
  1009	    state_.decoder_filter_chain_aborted_ = true;
  1010	  } else if (state_.filter_call_state_ & FilterCallState::IsEncodingMask) {
  1011	    state_.encoder_filter_chain_aborted_ = true;
  1012	  }
  1013	  // When independent half-close is enabled local reply always stops decoder filter chain.
  1014	  if (filter_manager_callbacks_.isHalfCloseEnabled()) {
  1015	    state_.decoder_filter_chain_aborted_ = true;
  1016	  }
  1017	
  1018	  streamInfo().setResponseCodeDetails(details);
  1019	  StreamFilterBase::LocalReplyData data{code, grpc_status, details, false};
  1020	  onLocalReply(data);
  1021	  if (data.reset_imminent_) {
  1022	    ENVOY_STREAM_LOG(debug, "Resetting stream due to {}. onLocalReply requested reset.", *this,
  1023	                     details);
  1024	    filter_manager_callbacks_.resetStream(Http::StreamResetReason::LocalReset, "");
  1025	    return;
  1026	  }
  1027	
  1028	  if (!filter_manager_callbacks_.responseHeaders().has_value() &&
  1029	      (!filter_manager_callbacks_.informationalHeaders().has_value() ||
  1030	       !(state_.filter_call_state_ & FilterCallState::IsEncodingMask))) {
  1031	    // If the response has not started at all, or if the only response so far is an informational
  1032	    // 1xx that has already been fully processed, send the response through the filter chain.
  1033	
  1034	    if (auto cb = filter_manager_callbacks_.downstreamCallbacks(); cb.has_value()) {
  1035	      // The initial route maybe never be set or the cached route maybe cleared by the filters.
  1036	      // This will force route refreshment if there is not a cached route to avoid potential
  1037	      // route refreshment in the response filter chain.
  1038	      cb->route(nullptr);
  1039	    }
  1040	    // We only prepare a local reply to execute later if we're actively invoking filters to avoid
  1041	    // re-entrant in filters.
  1042	    //
  1043	    // For reverse connections (where upstream initiates the connection to downstream), we need to
  1044	    // send local replies immediately rather than queuing them. This ensures proper handling of the
  1045	    // reversed connection flow and prevents potential issues with connection state and filter chain
  1046	    // processing.
