  auto result = header_validator_->transformResponseHeaders(headers);
  if (!result.status.ok()) {
    // TODO(yanavlasov): add handling for this case.    ← also untested, but intentional
  } else if (result.new_headers) {
    // Validator rewrote the headers; encode the replacement map
    response_encoder_->encodeHeaders(*result.new_headers, end_stream);  // ← NEVER reached
    return;
  }
}
// Fallthrough: encode original headers
